-- ============================================================
-- Tetherly — SaaS Seed (Neha & Naveen full mirror)
-- Run this AFTER supabase/schema_saas.sql in the SaaS project's
-- Database → SQL Editor.
-- ============================================================
--
-- Seeds the SaaS Supabase project (anezjniflzoxfzxyctja.supabase.co)
-- with a single wedding row plus the full N&N guest list, admins,
-- pre-collected RSVP data, song requests, and contact info — all
-- scoped by the tenant wedding_id below.
--
-- Tenant id:     a0000000-0000-0000-0000-000000000001
-- Invite code:   NEHANAVEEN2026    (change if desired — it's what
--                                   guests type on the /invite screen)
--
-- Idempotent: safe to re-run. Guests / admins / wedding row no-op
-- on conflict. guest_info upserts (keeps newer values). song_requests
-- are wiped for THIS wedding only and re-inserted, so re-running gets
-- a fresh song list without touching other tenants.
-- ============================================================



-- ─── Weddings ─────────────────────────────────────────────────────────────────
-- Seed the "Neha & Naveen" demo wedding. The fixed UUID matches the default
-- `wedding_id` on every data table; once all app queries pass wedding_id
-- explicitly (PR 3) those defaults come off.

  id, invite_code, couple_names, wedding_date, location, destination_city,
  hashtag, website, contact_email, registry_url, theme_color
) values (
  'a0000000-0000-0000-0000-000000000001',
  'NEHANAVEEN2026',
  'Neha & Naveen',
  '2026-05-23T15:00:00Z',
  'Montreux, Switzerland',
  'Montreux',
  '#NehaNaveen2026',
  'https://www.neha-naveen.com',
  'nehanaveen2026@gmail.com',
  'https://blissandbone.sendbirdie.com/r/neha-naveen',
  '#8B5E6B'
) on conflict (id) do nothing;


-- ─── Guests ───────────────────────────────────────────────────────────────────
-- Per-wedding guest list. Login validates the typed name against this table
-- (or against wedding_admins, for planners and other non-guest admins).
-- The 4th column flags the bridal party (bridesmaids/bridesman) — a subset
-- of the wedding party that gets extra packing items.

on conflict (wedding_id, canonical_name) do nothing;



-- ─── Wedding Admins ───────────────────────────────────────────────────────────
-- Users with admin access (send notifications, delete messages). May or may
-- not be in the guest list — e.g. the wedding planner is an admin but not a
-- guest.

-- is_wedding_party + gender are only consulted for admins who aren't in
-- public.guests. Neha and Naveen are both, so their admin-row flags are
-- harmless defaults. Astrid (planner) is tagged wedding-party + female
-- so she sees the rehearsal dinner and the women's packing list. DJ
-- Shraii logs in as "DJ Shraii" with role='dj' — login only, scoped to
-- Sangeet + Ceremony + Reception (no rehearsal dinner), no admin powers.
-- Shilpa Patel (makeup artist) is tagged wedding-party so she sees every
-- event the bride attends; role='makeup_artist' keeps her out of the admin UI.
on conflict (wedding_id, guest_name) do update set
  is_wedding_party = excluded.is_wedding_party,
  gender           = excluded.gender,
  role             = excluded.role;


-- ─── Guest Info ───────────────────────────────────────────────────────────────
-- Pre-populate dietary, meal choices, and rehearsal dinner attendance.
-- The app only updates hotel/arrival/notes; these fields are preserved.

on conflict (wedding_id, guest_name) do update set
  dietary          = excluded.dietary,
  meal_1           = excluded.meal_1,
  meal_2           = excluded.meal_2,
  meal_3           = excluded.meal_3,
  rehearsal_dinner = excluded.rehearsal_dinner;


-- ─── Song Requests ────────────────────────────────────────────────────────────
-- Pre-populated from RSVP responses.
-- To re-seed: run the DELETE first, then the INSERT.

delete from public.song_requests where wedding_id = 'a0000000-0000-0000-0000-000000000001';



-- ─── Contact Info ─────────────────────────────────────────────────────────────
